// ── Saves ─────────────────────────────────────────────────────────────────────

ipcMain.handle('write-save', (_, { slotKey, data }) => {
  const safe = slotKey.replace(/[^a-zA-Z0-9_\-]/g, '_');
  fs.writeFileSync(path.join(savesDir, safe + '.json'), JSON.stringify(data, null, 2), 'utf-8');
  return { ok: true };
});

ipcMain.handle('read-save', (_, slotKey) => {
  const safe = slotKey.replace(/[^a-zA-Z0-9_\-]/g, '_');
  const p = path.join(savesDir, safe + '.json');
  if (!fs.existsSync(p)) return null;
  try { return JSON.parse(fs.readFileSync(p, 'utf-8')); } catch { return null; }
});

ipcMain.handle('list-saves', () => {
  if (!fs.existsSync(savesDir)) return [];
  return fs.readdirSync(savesDir).filter(f => f.endsWith('.json')).map(f => f.slice(0, -5));
});

ipcMain.handle('delete-save', (_, slotKey) => {
  const safe = slotKey.replace(/[^a-zA-Z0-9_\-]/g, '_');
  const p = path.join(savesDir, safe + '.json');
  if (fs.existsSync(p)) fs.unlinkSync(p);
  return { ok: true };
});

// ── Settings ──────────────────────────────────────────────────────────────────

ipcMain.handle('write-setting', (_, { key, value }) => {
  const safe = key.replace(/[^a-zA-Z0-9_\-]/g, '_');
  if (!fs.existsSync(settingsDir)) fs.mkdirSync(settingsDir, { recursive: true });
  fs.writeFileSync(path.join(settingsDir, safe + '.json'), JSON.stringify(value, null, 2), 'utf-8');
  return { ok: true };
});

ipcMain.handle('read-setting', (_, key) => {
  const safe = key.replace(/[^a-zA-Z0-9_\-]/g, '_');
  const p = path.join(settingsDir, safe + '.json');
  if (!fs.existsSync(p)) return null;
  try { return JSON.parse(fs.readFileSync(p, 'utf-8')); } catch { return null; }
});

// ── GLB export ─────────────────────────────────────────────────────────────────

ipcMain.handle('save-glb', async (_, { defaultName, buffer }) => {
  const result = await dialog.showSaveDialog(mainWindow, {
    title: 'Export GLB',
    defaultPath: defaultName,
    filters: [{ name: 'GL Binary', extensions: ['glb'] }],
  });
  if (result.canceled || !result.filePath) return { ok: false };
  fs.writeFileSync(result.filePath, Buffer.from(buffer));
  return { ok: true, filePath: result.filePath };
});
